def create_saml_response(user_id, user_email, user_attributes, in_response_to, destination):
    """Create a signed SAML response with proper security controls"""
    
    issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
    not_before = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
