        destination = request_xml.get('AssertionConsumerServiceURL')
        issuer = request_xml.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Issuer')
        
        if not request_id or not destination:
            return "Invalid SAML Request", 400
        
        # Validate issuer matches expected SP
